class OrderParser:
    """Stage 1: Parse raw order strings into structured data."""

    def parse(self, raw_order):
        items = []
        for line in raw_order.strip().split('\n'):
            parts = line.split(',')
            if len(parts) >= 3:
                items.append({
                    'name': parts[0].strip(),
                    'quantity': int(parts[1].strip()),
                    'price': float(parts[2].strip()),
                })
        return {'items': items, 'status': 'parsed'}

