class OrderValidator:
    """Stage 2: Validate order data and apply basic business rules."""

    def __init__(self, max_quantity=100, max_price=10000):
        self.max_quantity = max_quantity
        self.max_price = max_price

    def validate(self, order):
        for item in order['items']:
            if item['quantity'] <= 0:
                raise ValueError(f"Invalid quantity for {item['name']}")
            if item['quantity'] > self.max_quantity:
                raise ValueError(f"Quantity exceeds max for {item['name']}")
            if item['price'] <= 0:
                raise ValueError(f"Invalid price for {item['name']}")
            if item['price'] > self.max_price:
                raise ValueError(f"Price exceeds max for {item['name']}")
            # BUG: Validator should NOT modify data, only validate
            if 'discount_pct' in item:
                item['price'] = item['price'] * (1 - item['discount_pct'] / 100)
        order['status'] = 'validated'
        return order

