class OrderEnricher:
    """Stage 3: Enrich order with tax rates and metadata."""

    def __init__(self, tax_rate=0.08, currency='USD'):
        self._tax_rate = tax_rate
        self._currency = currency

    def enrich(self, order):
        for item in order['items']:
            # BUG: Should be self._tax_rate (with underscore)
            item['tax_rate'] = self.tax_rate
            item['currency'] = self._currency
        order['status'] = 'enriched'
        return order

    def __getattr__(self, name):
        # Silently returns 0 for missing attributes
        return 0

