class OrderDiscounter:
    """Stage 5: Apply discounts to items."""

    def __init__(self, bulk_threshold=10, bulk_discount=0.05):
        self.bulk_threshold = bulk_threshold
        self.bulk_discount = bulk_discount

    def apply_discounts(self, order):
        for item in order['items']:
            discount = 0
            if item['quantity'] >= self.bulk_threshold:
                discount = self.bulk_discount
            if 'discount_pct' in item:
                discount += item['discount_pct'] / 100
            item['discount_amount'] = item['subtotal'] * discount
            item['after_discount'] = item['subtotal'] - item['discount_amount']
        order['status'] = 'discounted'
        return order

