class OrderTaxer:
    """Stage 6: Apply tax to items."""

    def apply_tax(self, order):
        for item in order['items']:
            tax_rate = item.get('tax_rate', 0)
            item['tax_amount'] = item['after_discount'] * tax_rate
            item['computed_total'] = item['after_discount'] + item['tax_amount']
        order['status'] = 'taxed'
        return order
